using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using System.Data.SqlClient;
using System.Text;

public static async Task<HttpResponseMessage> Run(
    [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequest req,
    ILogger log)
{
    string connectionString = "YOUR_CONNECTION_STRING";
    string tableName = "YOUR_TABLE_NAME";

    string query = "SELECT * FROM " + tableName + " WHERE 1 = 1";

    StringBuilder whereClause = new StringBuilder();

    foreach (var parameter in req.Query)
    {
        if (parameter.Key.StartsWith("filter:"))
        {
            string filter = parameter.Value;
            whereClause.Append(" AND " + parameter.Key.Substring(7) + " = '" + filter + "'");
        }
    }

    if (whereClause.Length > 0)
    {
        query += whereClause.ToString();
    }

    using (SqlConnection connection = new SqlConnection(connectionString))
    {
        await connection.OpenAsync();

        using (SqlCommand command = new SqlCommand(query, connection))
        {
            SqlDataReader reader = await command.ExecuteReaderAsync();

            string result = "";
            while (await reader.ReadAsync())
            {
                result += reader.GetString(0) + ",";
            }

            reader.Close();

            return new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent(result)
            };
        }
    }
}